let pgOk = false;
try { if (pool) { const r = await pool.query('SELECT 1 as ok'); pgOk = r.rows[0].ok === 1; } } catch(e){}
msg.statusCode=200;
msg.payload={status:'ok', services:{postgres:pgOk, node_red:true}, ts:new Date().toISOString()};
