const REQ_TOPIC  = '$CONTROL/dynamic-security/v1';
const RESP_TOPIC = '$CONTROL/dynamic-security/v1/response';

const client = mqtt.connect('mqtt://mosquitto:1883', {
  clientId: 'nodered-dynsec-' + crypto.randomBytes(4).toString('hex'),
  username: env.get('MQTT_BRIDGE_USER') || 'nodered',
  password: env.get('MQTT_BRIDGE_PASSWORD'),
  protocolVersion: 5,
  clean: true,
  reconnectPeriod: 2000,
  connectTimeout: 5000
});

let subscribed = false;
let currentInflight = null; // {resolve, reject, timer, commands}
let serialQueue = Promise.resolve();

client.on('connect', () => {
  client.subscribe(RESP_TOPIC, {qos: 1}, (err) => {
    if (err) { node.error('dynsec sub: ' + err.message); node.status({fill:'red',shape:'ring',text:'sub fail'}); }
    else { subscribed = true; node.status({fill:'green', shape:'dot', text:'dynsec ready'}); }
  });
});

client.on('message', (topic, payload) => {
  if (topic !== RESP_TOPIC) return;
  if (!currentInflight) return;
  const { resolve, reject, timer, commands } = currentInflight;
  clearTimeout(timer);
  currentInflight = null;
  try {
    const body = JSON.parse(payload.toString());
    const responses = Array.isArray(body.responses) ? body.responses : [];
    if (responses.length !== commands.length) {
      return reject(new Error('dynsec: response count mismatch (expected ' + commands.length + ', got ' + responses.length + ')'));
    }
    for (let i = 0; i < commands.length; i++) {
      const expected = commands[i].command;
      const got = responses[i] && responses[i].command;
      if (got !== expected) {
        return reject(new Error('dynsec: command mismatch at ' + i + ' (expected ' + expected + ', got ' + got + ')'));
      }
      if (responses[i].error) {
        return reject(new Error('dynsec ' + expected + ': ' + responses[i].error));
      }
    }
    resolve(responses.map(r => r.data || {}));
  } catch (e) { reject(new Error('dynsec parse: ' + e.message)); }
});

client.on('error',     (e) => { node.warn('dynsec err: ' + e.message); node.status({fill:'red',shape:'ring',text:'err'}); });
client.on('reconnect', ()  => node.status({fill:'yellow',shape:'ring',text:'reconnecting...'}));
client.on('close',     ()  => node.status({fill:'yellow',shape:'ring',text:'disconnected'}));

function runBatch(commands, timeoutMs) {
  return new Promise((resolve, reject) => {
    if (!client.connected) return reject(new Error('dynsec not connected'));
    if (!subscribed)       return reject(new Error('dynsec not subscribed'));
    if (currentInflight)   return reject(new Error('dynsec busy (internal queue bug)'));
    const timer = setTimeout(() => {
      currentInflight = null;
      reject(new Error('dynsec timeout: ' + commands.map(c => c.command).join(',')));
    }, timeoutMs || 5000);
    currentInflight = { resolve, reject, timer, commands };
    client.publish(REQ_TOPIC, JSON.stringify({ commands }), { qos: 1 }, (err) => {
      if (err) {
        clearTimeout(timer);
        currentInflight = null;
        reject(err);
      }
    });
  });
}

global.set('dynsecClient', client);

// dynsecBatch: executa N comandos atomicamente, retorna array de `data`s
global.set('dynsecBatch', (commands, timeoutMs) => {
  const task = () => runBatch(commands, timeoutMs);
  const chained = serialQueue.then(task, task);
  serialQueue = chained.catch(() => {});
  return chained;
});

// dynsecCall: compatibilidade com chamadas single-command
global.set('dynsecCall', async (cmd, timeoutMs) => {
  const results = await global.get('dynsecBatch')([cmd], timeoutMs);
  return results[0];
});

