const pool = global.get('pgPool');
const baseUrl = global.get('mailBaseUrl') || env.get('MAIL_BASE_URL') || 'https://hub.xtconect.online';
function redirect(suffix) {
  msg.statusCode = 302;
  msg.headers = { Location: baseUrl + '/login?verified=' + suffix };
  msg.payload = '';
  return msg;
}
if (!pool) return redirect('error');
const token = (msg.req.query && msg.req.query.token) || '';
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!UUID_RE.test(token)) return redirect('invalid');
try {
  const r = await pool.query(
    "SELECT user_id, used_at, expires_at FROM email_verification_tokens WHERE token=$1 AND purpose='signup'",
    [token]
  );
  if (r.rowCount === 0) return redirect('notfound');
  const row = r.rows[0];
  if (row.used_at) return redirect('used');
  if (new Date(row.expires_at).getTime() < Date.now()) return redirect('expired');
  await pool.query('UPDATE app_users SET email_verified=TRUE WHERE id=$1', [row.user_id]);
  await pool.query('UPDATE email_verification_tokens SET used_at=now() WHERE token=$1', [token]);
  return redirect('true');
} catch(e) {
  node.error('verify: '+e.message, msg);
  return redirect('error');
}

const pool = global.get('pgPool');
const sendMail = global.get('sendMail');
const baseUrl = global.get('mailBaseUrl') || env.get('MAIL_BASE_URL') || 'https://hub.xtconect.online';
const okResp = { message: 'Se houver uma conta com este e-mail nao verificada, um novo link foi enviado.' };
if (!pool) { msg.statusCode=503; msg.payload={error:'db not ready'}; return msg; }
const body = msg.payload || {};
const email = (body.email||'').toLowerCase().trim();
if (!email) { msg.statusCode=200; msg.payload=okResp; return msg; }
try {
  const r = await pool.query('SELECT id, email_verified, full_name FROM app_users WHERE email=$1 LIMIT 1', [email]);
  if (r.rowCount === 0 || r.rows[0].email_verified) { msg.statusCode=200; msg.payload=okResp; return msg; }
  const u = r.rows[0];
  await pool.query("UPDATE email_verification_tokens SET used_at=now() WHERE user_id=$1 AND purpose='signup' AND used_at IS NULL", [u.id]);
  const tk = await pool.query(
    "INSERT INTO email_verification_tokens (user_id, purpose, expires_at) VALUES ($1,'signup', now()+interval '24 hours') RETURNING token",
    [u.id]
  );
  if (sendMail) {
    try {
      await sendMail({to: email, subject: 'Confirme seu e-mail — XT Connect Hub', template: 'signup-verify', vars: {nome: u.full_name || email, link: baseUrl + '/verify?token=' + tk.rows[0].token}});
    } catch(e) { node.warn('resend mail failed: '+e.message); }
  }
  msg.statusCode = 200; msg.payload = okResp;
} catch(e) {
  node.error('resend: '+e.message, msg);
  msg.statusCode = 200; msg.payload = okResp;
}
return msg;

const auth = (msg.req.headers['authorization']||'').trim();
const m = auth.match(/^Bearer (.+)$/);
if (!m) { msg.statusCode=401; msg.payload={error:'missing bearer token'}; return [null, msg]; }
try {
  const secret = env.get('JWT_SECRET');
  const decoded = jwt.verify(m[1], secret);
  if (decoded.typ === 'refresh') { msg.statusCode=401; msg.payload={error:'refresh token cannot be used here'}; return [null, msg]; }
  msg.user = { id: decoded.sub, email: decoded.email, role: decoded.role };
  return [msg, null];
} catch (e) { msg.statusCode=401; msg.payload={error:'invalid token'}; return [null, msg]; }

const pool = global.get('pgPool');
if (!pool) { msg.statusCode=503; msg.payload={error:'db not ready'}; return msg; }

const id = msg.req.params.id;
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!id || !UUID_RE.test(id)) { msg.statusCode=400; msg.payload={error:'id invalido'}; return msg; }

const q = msg.req.query || {};
let limit = parseInt(q.limit || '500', 10);
if (!Number.isFinite(limit) || limit <= 0) limit = 500;
if (limit > 2000) limit = 2000;

const sinceParam = q.since ? new Date(q.since) : null;
const untilParam = q.until ? new Date(q.until) : null;
const since = (sinceParam && !isNaN(sinceParam)) ? sinceParam.toISOString() : null;
const until = (untilParam && !isNaN(untilParam)) ? untilParam.toISOString() : null;

try {
  // 1) Lookup + AuthZ
  const sel = await pool.query(
    'SELECT id, user_id, admin_access_level FROM devices WHERE id=$1 LIMIT 1', [id]
  );
  if (sel.rowCount === 0) { msg.statusCode=404; msg.payload={error:'not found'}; return msg; }
  const dev = sel.rows[0];
  const isOwner = dev.user_id === msg.user.id;
  const isAdminWithAccess = msg.user.role === 'admin' && dev.admin_access_level !== 'none';
  if (!isOwner && !isAdminWithAccess) { msg.statusCode=403; msg.payload={error:'forbidden'}; return msg; }

  // 2) Query
  const r = await pool.query(`
    SELECT ts, payload
    FROM device_readings
    WHERE device_id = $1
      AND ts >= COALESCE($2::timestamptz, now() - interval '24 hours')
      AND ts <= COALESCE($3::timestamptz, now())
    ORDER BY ts DESC
    LIMIT $4
  `, [id, since, until, limit]);

  msg.statusCode = 200;
  msg.payload = { readings: r.rows.map(row => ({ ts: row.ts, payload: row.payload })) };
} catch (e) {
  node.error('get readings: ' + e.message, msg);
  msg.statusCode = 500; msg.payload = { error: 'internal' };
}
return msg;

// E2.3 — flip stale devices to offline usando threshold per-device (#51)
// Threshold efetivo = clamp(3 * telemetry_interval_s, 60, 900) segundos.
const pool = global.get('pgPool');
if (!pool) { node.status({ fill:'yellow', shape:'ring', text:'sem pool' }); return null; }
try {
  const r = await pool.query(
    `UPDATE devices
        SET is_online = FALSE
      WHERE is_online = TRUE
        AND last_seen IS NOT NULL
        AND last_seen < NOW() - MAKE_INTERVAL(
          secs => GREATEST(60, LEAST(900, telemetry_interval_s * 3))
        )
      RETURNING id, device_id AS serial, user_id, last_seen, telemetry_interval_s`
  );
  if (r.rowCount === 0) {
    node.status({ fill:'grey', shape:'dot', text:'nothing stale '+new Date().toISOString().slice(11,19) });
    return null;
  }
  const msgs = [];
  for (const row of r.rows) {
    const payload = {
      type: 'device_status_changed',
      online: false,
      device_id: row.id,
      serial: row.serial,
      user_id: row.user_id,
      last_seen_at: row.last_seen ? new Date(row.last_seen).toISOString() : null,
      source: 'sweeper'
    };
    msgs.push({ topic: 'devices/' + row.serial + '/status', payload: JSON.stringify(payload) });
  }
  node.status({ fill:'orange', shape:'dot', text:'flipped '+r.rowCount+' @ '+new Date().toISOString().slice(11,19) });
  for (const m of msgs) node.send(m);
} catch (e) {
  node.error('sweeper: '+e.message);
  node.status({ fill:'red', shape:'ring', text:e.message.slice(0,40) });
}
return null;

const auth = (msg.req.headers['authorization']||'').trim();
const m = auth.match(/^Bearer (.+)$/);
if (!m) { msg.statusCode=401; msg.payload={error:'missing bearer token'}; return [null, msg]; }
try {
  const secret = env.get('JWT_SECRET');
  const decoded = jwt.verify(m[1], secret);
  if (decoded.typ === 'refresh') { msg.statusCode=401; msg.payload={error:'refresh token cannot be used here'}; return [null, msg]; }
  msg.user = { id: decoded.sub, email: decoded.email, role: decoded.role, name: decoded.name };
  return [msg, null];
} catch(e) {
  msg.statusCode=401; msg.payload={error:'invalid token'}; return [null, msg];
}

// E2.3 — atualiza taxa (mode=default) ou só publica burst (mode=burst).
// Permissão: owner ou admin.
const pool = global.get('pgPool');
if (!pool) { msg.statusCode=503; msg.payload={error:'db not ready'}; return [msg, null]; }

const id = msg.req.params.id;
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!id || !UUID_RE.test(id)) { msg.statusCode=400; msg.payload={error:'id invalido'}; return [msg, null]; }

const body = msg.payload || {};
const mode = (body.mode === 'burst') ? 'burst' : (body.mode === 'default' ? 'default' : null);
if (!mode) { msg.statusCode=400; msg.payload={error:'mode deve ser default ou burst'}; return [msg, null]; }

const rate = Number(body.rate_s);
if (!Number.isFinite(rate) || !Number.isInteger(rate) || rate < 1) {
  msg.statusCode=400; msg.payload={error:'rate_s invalido'}; return [msg, null];
}
if (mode === 'default' && rate > 3600) {
  msg.statusCode=400; msg.payload={error:'rate_s (default) deve ser <= 3600'}; return [msg, null];
}
if (mode === 'burst' && rate > 60) {
  msg.statusCode=400; msg.payload={error:'rate_s (burst) deve ser <= 60'}; return [msg, null];
}

let durationS = 0;
if (mode === 'burst') {
  durationS = Number(body.duration_s);
  if (!Number.isFinite(durationS) || !Number.isInteger(durationS) || durationS < 5 || durationS > 1800) {
    msg.statusCode=400; msg.payload={error:'duration_s invalido (5..1800)'}; return [msg, null];
  }
}

try {
  const sel = await pool.query(
    'SELECT id, user_id, device_id FROM devices WHERE id=$1 LIMIT 1',
    [id]
  );
  if (sel.rowCount === 0) { msg.statusCode=404; msg.payload={error:'not found'}; return [msg, null]; }
  const dev = sel.rows[0];
  const isOwner = dev.user_id === msg.user.id;
  const isAdmin = msg.user && msg.user.role === 'admin';
  if (!isOwner && !isAdmin) { msg.statusCode=403; msg.payload={error:'forbidden'}; return [msg, null]; }

  if (mode === 'default') {
    await pool.query(
      'UPDATE devices SET telemetry_interval_s=$1 WHERE id=$2',
      [rate, id]
    );
  }

  const requestId = crypto.randomUUID();
  const cmd = {
    cmd: 'set_rate',
    rate_s: rate,
    mode,
    request_id: requestId
  };
  if (mode === 'burst') {
    cmd.expires_at = new Date(Date.now() + durationS * 1000).toISOString();
  }

  const pubMsg = {
    topic: 'devices/' + dev.device_id + '/commands',
    payload: JSON.stringify(cmd)
  };

  msg.statusCode = 200;
  msg.payload = { ok: true, request_id: requestId, applied_rate_s: rate, mode };
  return [msg, pubMsg];
} catch (e) {
  node.error('set rate: ' + e.message, msg);
  msg.statusCode = 500;
  msg.payload = { error: 'internal' };
  return [msg, null];
}
